import { formatGameResult } from './task07';

describe('formatGameResult', () => {
  it('4-player format', () => {
    expect(formatGameResult('1:2:3:4-12:8')).toBe('P1 vs P2 vs P3 vs P4 (12-8)');
  });

  it('2-player format', () => {
    expect(formatGameResult('1:2-5:3')).toBe('P1 vs P2 (5-3)');
  });

  it('null input returns empty string', () => {
    expect(formatGameResult(null as any)).toBe('');
  });
});
